INSERT INTO "public"."knowledge_articles" ("id", "slug", "category", "title_vi", "title_en", "expert_tip_vi", "expert_tip_en", "content_structure") VALUES ('18c859e5-0835-4d1a-8747-a9e0202b9574', 'pearson-correlation-analysis', 'Relationship Analysis', 'Tương quan Pearson: Bản đồ các mối liên kết', 'Pearson Correlation: The Connection Map', 'Hệ số tương quan r chạy từ -1 đến +1. Hãy cẩn thận với r > 0.8 giữa các biến độc lập - đó là dấu hiệu của Đa cộng tuyến (Multicollinearity).', 'Correlation r spans -1 to +1. Beware r > 0.8 between independents—a clear red flag for Multicollinearity.', '[{"h2_en":"1. Searching for Linkage","h2_vi":"1. Tìm kiếm sự liên kết","content_en":"Correlation measures how variables move together. Positive r: both increase; Negative r: one increases, one decreases. The prerequisite for Regression.","content_vi":"Tương quan đo lường mức độ các biến \"đi cùng nhau\". r dương: cả 2 cùng tăng; r âm: 1 cái tăng 1 cái giảm. Đây là tiền đề cho Hồi quy."},{"h2_en":"2. Practical Case: Reviews vs Sales","h2_vi":"2. Practical User Case: Review Online & Doanh số","content_en":"r = 0.65 (+). More KOL review views = higher purchase likelihood. ncsStat suggests investing in quality review content.","content_vi":"r = 0.65 (+). Khách càng xem Review KOLs nhiều, khả năng mua hàng càng cao. ncsStat gợi ý bạn nên đầu tư mạnh vào đội ngũ Reviewer chất lượng."}]'), ('4f08d201-ba6a-4a7d-adcb-d79233d814b9', 'independent-t-test-guide', 'Comparison Analysis', 'Independent T-test: So sánh các nhóm đối đầu', 'Independent T-test: Comparing Opposite Groups', 'Levene''s Test là "người gác cổng". Phải đảm bảo Sig > 0.05 trước khi đọc kết quả T-test ở dòng 1. Nếu không, ncsStat sẽ hướng dẫn bạn dòng 2.', 'Levene''s Test is the gatekeeper. Ensure Sig > 0.05 for Row 1 usage. Otherwise, ncsStat directs you to Row 2 results.', '[{"h2_en":"1. When to use T-test?","h2_vi":"1. Khi nào dùng T-test?","content_en":"Compare means between 2 distinct groups (e.g., Male vs Female). It determines if the difference is significant or just noise.","content_vi":"Khi bạn muốn so sánh trung bình giữa 2 nhóm hoàn toàn tách biệt (Vd: Nam vs Nữ, IOS vs Android). Phép thử này xác định sự khác biệt là thực lực hay ngẫu nhiên."},{"h2_en":"2. Practical Case: Customer Satisfaction","h2_vi":"2. Practical User Case: Sự hài lòng của Khách hàng","content_en":"Old vs New customers. Old Mean 4.5 > New 3.8. If Sig < 0.05, your retention campaign is scientifically successful.","content_vi":"So sánh mức hài lòng giữa Khách mới và Khách cũ. Mean Khách cũ 4.5 > Mới 3.8. Nếu Sig < 0.05, chiến dịch retention của bạn đang hoạt động rất tốt."}]'), ('5fa52d6b-a86b-43ae-be7b-c4258152ab31', 'chi-square-test-independence', 'Categorical Analysis', 'Kiểm định Chi-square: Liên kết dữ liệu định danh', 'Chi-square Test: Linking Categorical Data', 'Với các đặc điểm nhân khẩu học (Giới tính, Nghề nghiệp), Chi-square là vua. Hãy đọc thêm Cramer''s V trên ncsStat để biết độ mạnh của liên kết thực tế.', 'For demographics (Gender, Job), Chi-square is king. Read Cramer''s V on ncsStat to quantify the actual strength of the association.', '[{"h2_en":"1. The Essence of Crosstabs","h2_vi":"1. Bản chất của Bảng chéo (Crosstabs)","content_en":"Chi-square compares Observed vs Expected. If Sig < 0.05, \"Fate\" has linked your two categorical variables together.","content_vi":"Chi-square so sánh cái Thực tế với cái Kỳ vọng. Nếu Sig < 0.05, \"Định mệnh\" đã kết nối 2 biến định danh của bạn lại với nhau."},{"h2_en":"2. Practical Case: Region vs Taste","h2_vi":"2. Practical User Case: Vùng miền & Khẩu vị","content_en":"Do North/Cent/South regions prefer different sweetness? Chi-square Sig = 0.000 confirms strong regional culinary cultural differences.","content_vi":"Kiểm tra: Người miền Bắc/Trung/Nam có gu ăn ngọt khác nhau không? Chi-square kết luận Sig = 0.000 -> Có sự khác biệt văn hóa vùng miền cực mạnh trong ẩm thực."}]'), ('618d61ed-5e45-48b9-afb6-e31e18fb8880', 'data-cleaning-outliers-detection', 'Preliminary Analysis', 'Làm sạch dữ liệu & Outliers: Vệ sinh Khoa học', 'Data Cleaning & Outliers: Scientific Scrubbing', 'Đừng xóa Outlier một cách máy móc. Hãy dùng Mahalanobis Distance trên ncsStat để phát hiện những người "trả lời lụi" (vd: tất cả chọn 1 hoặc 5).', 'Don''t delete outliers blindly. Use Mahalanobis Distance on ncsStat to detect "junk responders" (e.g., all 1s or all 5s).', '[{"h2_en":"1. The Model Killer: Outliers","h2_vi":"1. Kẻ hủy diệt Mô hình: Outliers","content_en":"Outliers are extreme data points that skew averages. Cleaning data is mandatory to hear the true voice of your sample.","content_vi":"Outliers là những điểm dữ liệu \"cực đoan\" làm lệch kết quả trung bình. Làm sạch dữ liệu là bước vệ sinh buộc phải làm để nghe được tiếng nói thực của mẫu."},{"h2_en":"2. Practical Case: Attitude Survey","h2_vi":"2. Practical User Case: Khảo sát thái độ","content_en":"One responder gives 1/5 for 100 questions (junk responding). ncsStat filters this to ensure the department''s satisfaction index stays accurate.","content_vi":"Một người khai 1 điểm cho toàn bộ 100 câu hỏi (trình trạng trả lời lụi). ncsStat sẽ giúp bạn gạt bỏ trường hợp này để chỉ số hài lòng của phòng ban không bị kéo tụt oan uổng."}]'), ('8bdc92e3-f365-4c4a-8dd5-e5e6475c2b66', 'mediation-analysis-sobel-test', 'Advanced Analysis', 'Biến trung gian (Mediation): Giải mã cơ chế tác động', 'Mediation Analysis: Decoding Core Mechanisms', 'Sử dụng kỹ thuật Bootstrapping của ncsStat để có khoảng tin cậy 95%. Nó uy tín hơn rất nhiều so với phép thử Sobel truyền thống trong các tạp chí Scopus/ISI.', 'Use ncsStat Bootstrapping for 95% Confidence Intervals. It is far more credible than the traditional Sobel test in Scopus/ISI journals.', '[{"h2_en":"1. Searching for the \"Transfer Station\"","h2_vi":"1. Tìm kiếm \"Trạm trung chuyển\"","content_en":"A mediator M explains \"Why X leads to Y?\". X impacts M, which then impacts Y. ncsStat decodes this vital link.","content_vi":"Biến trung gian M giải thích \"Tại sao X lại dẫn đến Y?\". X tác động đến M, và từ M mới tác động đến Y. ncsStat giải mã mắt xích quan trọng này."},{"h2_en":"2. Practical Case: CSR & Reputation","h2_vi":"2. Practical User Case: Thiện nguyện & Danh tiếng","content_en":"CSR (X) boosts Trust (M), which then increases Purchase Intent (Y). Without Trust, CSR actions may not directly translate to sales.","content_vi":"CSR (X) làm tăng Lòng tin khách hàng (M), và Lòng tin mới làm tăng Ý định mua (Y). Nếu không có Lòng tin, thiện nguyện chưa chắc sinh ra doanh số ngay."}]'), ('8e397995-1e34-4ee7-9b5c-8211b41683bf', 'efa-factor-analysis', 'Factor Analysis', 'Phân tích nhân tố khám phá (EFA): Khám phá cấu trúc ẩn', 'Exploratory Factor Analysis (EFA): Discovering Inner Structures', 'Trong nghiên cứu xã hội, hãy ưu tiên phép xoay Promax. Nó cho phép các nhân tố tương quan - phản ánh đúng bản chất hành vi con người hơn Varimax.', 'Prioritize Promax rotation in social sciences. It allows correlated factors, which reflects real human behavior better than Varimax.', '[{"h2_en":"1. The Essence of Data Grouping","h2_vi":"1. Bản chất của việc gom nhóm dữ liệu","content_en":"EFA uncovers invisible strings connecting variables. It assumes a few underlying \"mother factors\" control dozens of survey responses.","content_vi":"EFA giúp chúng ta tìm thấy những \"sợi dây vô hình\" kết nối các biến. Nó giả định rằng đằng sau hàng chục câu hỏi khảo sát là một vài \"nhân tố mẹ\" đang điều khiển tất cả."},{"h2_en":"2. Strict Control Metrics","h2_vi":"2. Các chỉ số Kiểm soát Chặt chẽ","content_en":"• KMO: ≥ 0.5 (Ideal > 0.7).\n• Bartlett''s: Sig < 0.05.\n• Loading: ≥ 0.5.\n• Cumulative Variance: > 50%.","content_vi":"• KMO: ≥ 0.5 (Tốt nhất > 0.7).\n• Bartlett''s Test: Sig < 0.05.\n• Factor Loading: Phải ≥ 0.5.\n• Phương sai trích: Phải > 50%."},{"h2_en":"3. Practical Case: Workplace Motivation","h2_vi":"3. Practical User Case: Động lực làm việc","content_en":"Survey 30 items. ncsStat clusters them into 5 groups: Salary, Environment, Boss, Peers, Opportunity. Precision targeting for HR strategy.","content_vi":"Khảo sát 30 yếu tố. ncsStat gom thành 5 nhóm: Lương thưởng, Môi trường, Sếp, Đồng nghiệp và Cơ hội. Giúp doanh nghiệp định vị đúng điểm cần cải thiện."}]'), ('a249e161-f2a9-4bb2-b8a4-54b14b3ac709', 'sem-cfa-structural-modeling', 'Advanced Analysis', 'Mô hình SEM và CFA: Đỉnh cao học thuật toàn cầu', 'SEM & CFA: The Academic Pinnacle', 'Chuẩn CFA yêu cầu RMSEA < 0.08 và CFI/TLI > 0.9. ncsStat cung cấp MI (Modification Indices) để bạn tinh chỉnh mô hình một cách thông minh nhất.', 'CFA standards: RMSEA < 0.08 and CFI/TLI > 0.9. ncsStat provides MIs for intelligent model refinement.', '[{"h2_en":"1. Modern Statistical Vision 2026","h2_vi":"1. Tầm nhìn Thống kê Hiện đại 2026","content_en":"SEM combines EFA and Regression, testing complex theoretical systems simultaneously. It is the crown of every ISI paper.","content_vi":"SEM là sự kết hợp của EFA và Hồi quy, cho phép kiểm định toàn bộ hệ thống lý thuyết phức tạp cùng lúc. Nó là \"vương miện\" của mọi bài nghiên cứu ISI."}]'), ('a71c578e-4a4a-4d0d-89fe-e27fcc5fd50c', 'descriptive-statistics-interpretation', 'Preliminary Analysis', 'Thống kê mô tả: Nghệ thuật kể chuyện qua con số', 'Descriptive Statistics: The Art of Storytelling', 'Hãy nhìn vào Mean và Std. Deviation. Độ lệch chuẩn thấp thể hiện sự đồng thuận; Cao thể hiện sự phân hóa thị trường rất mạnh.', 'Low SD means consensus; High SD indicates strong market polarization. Always report both Mean and SD.', '[{"h2_en":"1. The Language of Reality","h2_vi":"1. Ngôn ngữ của Thực tế","content_en":"Descriptive stats summarize populations. Mean, Median, and Mode help identify who the \"average customer\" truly is.","content_vi":"Thống kê mô tả giúp tóm tắt đám đông thành các chỉ số dễ hiểu. Mean, Median, và Mode giúp chúng ta hiểu \"khách hàng trung bình\" là ai."},{"h2_en":"2. Normality Check","h2_vi":"2. Phân phối chuẩn (Normality)","content_en":"Use Skewness and Kurtosis to check for bias. This is the mandatory entry ticket before using T-tests or ANOVA.","content_vi":"Sử dụng Skewness và Kurtosis để biết dữ liệu có bị \"lệch\" không. Đây là tấm vé thông hành bắt buộc trước khi dùng T-test hay ANOVA."},{"h2_en":"3. Practical Case: Gen Z Income","h2_vi":"3. Practical User Case: Thu nhập Gen Z","content_en":"Mean 15M vs Median 8M. A few \"whales\" skew the mean. ncsStat suggests using Median to reflect the genuine Gen Z reality.","content_vi":"Mean 15tr nhưng Median chỉ 8tr do có vài Case \"cá mập\" kéo Mean lên. ncsStat khuyên bạn dùng Median để thấy đúng thực tế tệp Gen Z."}]'), ('b04a2b20-e6dd-41a3-afd0-dcdb63b4abeb', 'regression-vif-multicollinearity', 'Impact Analysis', 'Hồi quy đa biến và Đa cộng tuyến (VIF): Dự báo Tác động', 'Multiple Regression & VIF: Predicting the Future', 'Hãy chú ý hệ số Beta chuẩn hóa. Nó giúp bạn so sánh chính xác mức độ quan trọng giữa các biến (vd: Quảng cáo vs Chăm sóc khách hàng).', 'Focus on Standardized Beta to compare the relative importance of variables like Ad Budget vs. Customer Service.', '[{"h2_en":"1. The Management Compass","h2_vi":"1. La bàn điều hướng Quản trị","content_en":"OLS regression predicts Y based on X. It is the most powerful forecasting tool for strategic planners.","content_vi":"Hồi quy OLS trả lời: \"Nếu tôi thay đổi X một đơn vị, Y sẽ thay đổi bao nhêu?\". Đây là công cụ dự báo quyền lực nhất cho các nhà hoạch định chiến lược."},{"h2_en":"2. Controlling Multicollinearity","h2_vi":"2. Kiểm soát Đa cộng tuyến (VIF)","content_en":"VIF must be < 10 (Strictly < 5). High VIF means independent variables overlap too much, biasing your model results.","content_vi":"VIF phải < 10 (Lý tưởng < 2 hoặc 5). Nếu VIF quá cao, các biến độc lập đang \"dẫm chân lên nhau\", làm sai lệch kết quả dự báo của mô hình."},{"h2_en":"3. Practical Case: Marketing ROI","h2_vi":"3. Practical User Case: Doanh thu Marketing","content_en":"Regressing TikTok vs FB ads on Sales. ncsStat shows TikTok Beta 0.45, FB Beta 0.22. TikTok is twice as effective for this segment.","content_vi":"Chạy hồi quy chi phí TikTok và FB Ads lên Doanh số. ncsStat chỉ ra Beta TikTok = 0.45, FB = 0.22. TikTok hiệu quả gấp đôi cho tệp khách này."}]'), ('b2a87267-4498-4b3f-b3df-b2a4e5928462', 'cronbach-alpha', 'Preliminary Analysis', 'Kiểm định Cronbach''s Alpha: Bản giao hưởng của Tin cậy nội tại', 'Cronbach''s Alpha Reliability Test: The Symphony of Internal Consistency', 'Đừng để bị đánh lừa bởi một con số Alpha tổng thấp. Hãy tập trung vào cột "Corrected Item-Total Correlation". Bất kỳ biến nào < 0.3 đều là "biến rác" cần loại bỏ ngay để làm sạch thang đo.', 'Focus on "Corrected Item-Total Correlation". Any item < 0.3 is noise and should be removed to purify your scale.', '[{"h2_en":"1. Deep Essence & Research Philosophy","h2_vi":"1. Bản chất & Triết lý nghiên cứu Chuyên sâu","content_en":"Based on Hair et al. (2010), Cronbach''s Alpha measures internal consistency. A reliable scale is the vital foundation for subsequent EFA and Regression models.","content_vi":"Theo tiêu chuẩn Hair et al. (2010), Cronbach''s Alpha đo lường mức độ các câu hỏi trong cùng một thang đo \"hiểu ý nhau\". Một thang đo tốt là nền tảng sống còn cho mọi phân tích EFA hay Hồi quy sau này."},{"h2_en":"2. Scopus/ISI Academic Standards","h2_vi":"2. Ma trận Tiêu chuẩn học thuật Scopus/ISI","content_en":"• 0.8 - 0.9: Excellent.\n• 0.7 - 0.8: Good.\n• 0.6 - 0.7: Acceptable for exploratory study.","content_vi":"• 0.8 - 0.9: Tuyệt vời (Standard Gold).\n• 0.7 - 0.8: Tốt (Research Standard).\n• 0.6 - 0.7: Chấp nhận được cho nghiên cứu sơ bộ.\n• < 0.6: Loại bỏ hoàn toàn."},{"h2_en":"3. Practical Case: Customer Loyalty","h2_vi":"3. Practical User Case: Lòng trung thành khách hàng","content_en":"Survey item \"Low price\" often clashes with psychological loyalty items. ncsStat helps identify and remove this dissonance to reach Alpha 0.78.","content_vi":"Nghiên cứu 4 câu: Mua lại, Giới thiệu, Tự hào, và Giá rẻ. ncsStat phát hiện câu \"Giá rẻ\" làm Alpha thấp (0.52). Loại bỏ nó, Alpha vọt lên 0.78 - cực kỳ đáng tin cậy."}]'), ('cccdcbe8-b869-4881-8e27-6cdf5989009b', 'one-way-anova-post-hoc', 'Comparison Analysis', 'Phân tích ANOVA: So sánh Đa nhóm chuyên sâu', 'One-way ANOVA: Deep Multi-group Analysis', 'Phép thử Post-hoc (Tukey/Games-Howell) là linh hồn của ANOVA. Nó giúp bạn chỉ ra chính xác cặp nào khác nhau, không chỉ nói chung chung "có khác biệt".', 'Post-hoc tests (Tukey/Games-Howell) are the soul of ANOVA. They pinpoint exactly which pairs differ, not just "there is a difference".', '[{"h2_en":"1. T-test Limits & ANOVA Power","h2_vi":"1. Giới hạn của T-test và Sức mạnh ANOVA","content_en":"ANOVA handles 3+ groups. It solves: \"Does Education (Bachelor/Master/PhD) change spending behavior?\".","content_vi":"ANOVA so sánh từ 3 nhóm trở lên. Nó giải quyết bài toán: \"Liệu trình độ học vấn (Đại học/Thạc sĩ/Tiến sĩ) có làm thay đổi hành vi chi tiêu?\""},{"h2_en":"2. Practical Case: Spending by Income Levels","h2_vi":"2. Practical User Case: Chi tiêu theo Thu nhập","content_en":"Low/Mid/High income. ANOVA says significant. Post-hoc reveals Mid & High spend similarly, Low spends significantly less. Optimal targeting logic.","content_vi":"Chia 3 nhóm thu nhập: Thấp, Trung, Cao. ANOVA báo có khác biệt. Post-hoc chỉ ra nhóm Trung và Cao chi tương đương, nhóm Thấp chi kém hẳn. Giúp Marketing tối ưu phân khúc."}]') ON CONFLICT (id) DO NOTHING;